import{_ as s,c as a,o as e,a as n}from"./app.09cc872b.js";const f=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[{"level":2,"title":"Verify","slug":"verify","link":"#verify","children":[]},{"level":2,"title":"TUI","slug":"tui","link":"#tui","children":[]},{"level":2,"title":"Configuration","slug":"configuration","link":"#configuration","children":[]},{"level":2,"title":"Test an attack","slug":"test-an-attack","link":"#test-an-attack","children":[]},{"level":2,"title":"Troubleshooting","slug":"troubleshooting","link":"#troubleshooting","children":[]}],"relativePath":"openshield-xdp/guide/quick-start.md","lastUpdated":1782412920000}'),t={name:"openshield-xdp/guide/quick-start.md"},o=n(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-hidden="true">#</a></h1><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">sudo openshield load        </span><span style="color:#676E95;"># Full TUI dashboard</span></span>
<span class="line"><span style="color:#A6ACCD;">sudo openshield load --stats-off   </span><span style="color:#676E95;"># Daemon mode (systemd)</span></span>
<span class="line"><span style="color:#A6ACCD;">sudo openshield load --stats-minimal  </span><span style="color:#676E95;"># Text snapshots</span></span>
<span class="line"><span style="color:#A6ACCD;">sudo openshield load -t 3600   </span><span style="color:#676E95;"># Auto-unload after 1 hour</span></span>
<span class="line"></span></code></pre></div><p>If you hit a BPF error:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">sudo openshield fix </span><span style="color:#89DDFF;">&amp;&amp;</span><span style="color:#A6ACCD;"> sudo openshield load</span></span>
<span class="line"></span></code></pre></div><h2 id="verify" tabindex="-1">Verify <a class="header-anchor" href="#verify" aria-hidden="true">#</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">$ sudo openshield status</span></span>
<span class="line"><span style="color:#A6ACCD;">OpenShield-XDP Status</span></span>
<span class="line"><span style="color:#A6ACCD;">=====================</span></span>
<span class="line"><span style="color:#A6ACCD;">  XDP Program:  LOADED</span></span>
<span class="line"><span style="color:#A6ACCD;">  Loader:       RUNNING</span></span>
<span class="line"><span style="color:#A6ACCD;">  Telemetry:    AVAILABLE</span></span>
<span class="line"><span style="color:#A6ACCD;">  Interface:    eno1</span></span>
<span class="line"><span style="color:#A6ACCD;">  XDP Mode:     native</span></span>
<span class="line"></span></code></pre></div><h2 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-hidden="true">#</a></h2><p>7 interactive screens. Press <code>1</code>\u2013<code>7</code> to switch between Dashboard, Traffic, Attacks, Bans, Logs, Status, and Config. Press <code>?</code> for help.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-hidden="true">#</a></h2><p>Edit <code>/etc/openshield/openshield.yaml</code>. See <a href="/openshield-xdp/configuration/reference">Configuration Reference</a> for the full reference.</p><h2 id="test-an-attack" tabindex="-1">Test an attack <a class="header-anchor" href="#test-an-attack" aria-hidden="true">#</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">hping3 -S --flood -p 80 </span><span style="color:#89DDFF;">&lt;</span><span style="color:#A6ACCD;">target</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">    </span><span style="color:#676E95;"># SYN flood</span></span>
<span class="line"><span style="color:#A6ACCD;">openshield-tui                        </span><span style="color:#676E95;"># Watch the dashboard</span></span>
<span class="line"></span></code></pre></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-hidden="true">#</a></h2><table><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>BPF load error</td><td><code>sudo openshield fix &amp;&amp; sudo openshield load</code></td></tr><tr><td>TUI stuck at Loading</td><td>Loader not running \u2014 start with <code>openshield load --stats-off</code></td></tr><tr><td>Another instance running</td><td><code>sudo openshield unload</code></td></tr><tr><td>Config not applying</td><td><code>sudo openshield reload</code></td></tr></tbody></table>`,14),l=[o];function i(d,p,r,c,h,u){return e(),a("div",null,l)}const y=s(t,[["render",i]]);export{f as __pageData,y as default};
